import React from 'react';
import { NavLink } from 'react-router-dom';

function DashboardSidebar({ isAdmin, isOpen = false, onClose = () => {} }) {
  const mainMenuItems = [
    {
      label: '대시보드',
      path: '/dashboard',
      desc: '요약 현황',
      icon: (
        <svg viewBox="0 0 24 24" aria-hidden="true">
          <rect x="4" y="4" width="7" height="7" rx="2" />
          <rect x="13" y="4" width="7" height="11" rx="2" />
          <rect x="4" y="13" width="7" height="7" rx="2" />
          <rect x="13" y="17" width="7" height="3" rx="1.5" />
        </svg>
      ),
    },
    {
      label: '대화 내역',
      path: '/dashboard/chat-history',
      desc: '히스토리 보기',
      icon: (
        <svg viewBox="0 0 24 24" aria-hidden="true">
          <path d="M7 18l-3 2V6a2 2 0 012-2h12a2 2 0 012 2v10a2 2 0 01-2 2H7z" />
          <path d="M8 9h8M8 13h6" />
        </svg>
      ),
    },
    {
      label: '보안 설정',
      path: '/dashboard/security',
      desc: '보안/세션 관리',
      icon: (
        <svg viewBox="0 0 24 24" aria-hidden="true">
          <path d="M12 3l7 3v5c0 5-3.4 8-7 10-3.6-2-7-5-7-10V6l7-3z" />
          <path d="M10 12l1.5 1.5L15 10" />
        </svg>
      ),
    },
    {
      label: '리포트',
      path: '/dashboard/reports',
      desc: '주간 인사이트',
      icon: (
        <svg viewBox="0 0 24 24" aria-hidden="true">
          <path d="M6 20V9M12 20V4M18 20v-7" />
        </svg>
      ),
    },
    {
      label: '개인정보 관리',
      path: '/dashboard/personal-info',
      desc: '프로필 편집',
      icon: (
        <svg viewBox="0 0 24 24" aria-hidden="true">
          <path d="M12 12a4 4 0 100-8 4 4 0 000 8z" />
          <path d="M5 20a7 7 0 0114 0" />
        </svg>
      ),
    },
    {
      label: '개인 설정',
      path: '/dashboard/settings',
      desc: '테마/알림 설정',
      icon: (
        <svg viewBox="0 0 24 24" aria-hidden="true">
          <path d="M12 8.8A3.2 3.2 0 1012 15.2 3.2 3.2 0 0012 8.8z" />
          <path d="M19 12a7 7 0 00-.09-1.1l2.01-1.56-1.9-3.28-2.43.76a7.24 7.24 0 00-1.9-1.1L14.3 3h-4.6l-.39 2.72a7.24 7.24 0 00-1.9 1.1l-2.43-.76-1.9 3.28 2.01 1.56A7 7 0 005 12c0 .37.03.74.09 1.1l-2.01 1.56 1.9 3.28 2.43-.76c.58.45 1.22.82 1.9 1.1L9.7 21h4.6l.39-2.72c.68-.28 1.32-.65 1.9-1.1l2.43.76 1.9-3.28-2.01-1.56c.06-.36.09-.73.09-1.1z" />
        </svg>
      ),
    },
  ];

  const adminMenuItems = [
    {
      label: '사용자 관리',
      path: '/admin',
      desc: '운영 모니터링',
      icon: (
        <svg viewBox="0 0 24 24" aria-hidden="true">
          <path d="M17 21v-2a4 4 0 00-4-4H7a4 4 0 00-4 4v2" />
          <circle cx="9" cy="7" r="4" />
          <path d="M23 21v-2a4 4 0 00-3-3.87" />
          <path d="M16 3.13a4 4 0 010 7.75" />
        </svg>
      ),
    },
    {
      label: '통계',
      path: '/admin/stats',
      desc: '성과 지표 보기',
      icon: (
        <svg viewBox="0 0 24 24" aria-hidden="true">
          <path d="M6 20V10" />
          <path d="M12 20V4" />
          <path d="M18 20v-8" />
        </svg>
      ),
    },
    {
      label: '시스템 설정',
      path: '/admin/system',
      desc: '환경 설정',
      icon: (
        <svg viewBox="0 0 24 24" aria-hidden="true">
          <path d="M12 8.8A3.2 3.2 0 1012 15.2 3.2 3.2 0 0012 8.8z" />
          <path d="M19 12a7 7 0 00-.09-1.1l2.01-1.56-1.9-3.28-2.43.76a7.24 7.24 0 00-1.9-1.1L14.3 3h-4.6l-.39 2.72a7.24 7.24 0 00-1.9 1.1l-2.43-.76-1.9 3.28 2.01 1.56A7 7 0 005 12c0 .37.03.74.09 1.1l-2.01 1.56 1.9 3.28 2.43-.76c.58.45 1.22.82 1.9 1.1L9.7 21h4.6l.39-2.72c.68-.28 1.32-.65 1.9-1.1l2.43.76 1.9-3.28-2.01-1.56c.06-.36.09-.73.09-1.1z" />
        </svg>
      ),
    },
  ];

  const accountMenuItems = [
    {
      label: '내 정보',
      path: '/mypage',
      desc: '개인 대시보드',
      icon: (
        <svg viewBox="0 0 24 24" aria-hidden="true">
          <path d="M4 7a3 3 0 013-3h10a3 3 0 013 3v10a3 3 0 01-3 3H7a3 3 0 01-3-3V7z" />
          <path d="M8 10h8M8 14h5" />
        </svg>
      ),
    },
  ];

  const handleItemClick = () => {
    if (window.innerWidth <= 1000) {
      onClose();
    }
  };

  const renderMenuItems = (items) =>
    items.map((item) => (
      <NavLink
        key={item.path}
        to={item.path}
        end={item.path === '/dashboard' || item.path === '/admin' || item.path === '/mypage'}
        className={({ isActive }) => `sidebar-item ${isActive ? 'active' : ''}`}
        onClick={handleItemClick}
      >
        <span className="sidebar-icon">{item.icon}</span>

        <span className="sidebar-text-group">
          <span className="sidebar-label">{item.label}</span>
          <span className="sidebar-desc">{item.desc}</span>
        </span>

        <span className="sidebar-arrow" aria-hidden="true">
          <svg viewBox="0 0 24 24">
            <path
              d="M9 6l6 6-6 6"
              fill="none"
              stroke="currentColor"
              strokeWidth="2"
              strokeLinecap="round"
              strokeLinejoin="round"
            />
          </svg>
        </span>
      </NavLink>
    ));

  return (
    <>
      <div
        className={`dashboard-sidebar-overlay ${isOpen ? 'is-open' : ''}`}
        onClick={onClose}
        aria-hidden="true"
      />

      <aside className={`dashboard-sidebar ${isOpen ? 'is-open' : ''}`}>
        <div className="dashboard-sidebar-panel">
          <div className="dashboard-sidebar-top">
            <div className="dashboard-sidebar-brand">
              <div className="dashboard-sidebar-brand-mark">A</div>
              <div className="dashboard-sidebar-brand-text">
                <strong>AI Care</strong>
                <span>Professional Dashboard</span>
              </div>
            </div>

            <button
              type="button"
              className="dashboard-sidebar-close"
              onClick={onClose}
              aria-label="사이드바 닫기"
            >
              <span />
              <span />
            </button>
          </div>

          <div className="dashboard-sidebar-scroll dashboard-sidebar-scroll--menus-only">
            <div className="sidebar-section">
              <div className="sidebar-title">메인</div>
              <div className="sidebar-menu">{renderMenuItems(mainMenuItems)}</div>
            </div>

            {isAdmin && (
              <div className="sidebar-section">
                <div className="sidebar-title">관리자</div>
                <div className="sidebar-menu">{renderMenuItems(adminMenuItems)}</div>
              </div>
            )}

            <div className="sidebar-section">
              <div className="sidebar-title">계정</div>
              <div className="sidebar-menu">{renderMenuItems(accountMenuItems)}</div>
            </div>
          </div>
        </div>
      </aside>
    </>
  );
}

export default DashboardSidebar;
